//! The idle maintenance runtime: activity signalling and the consolidation worker.

use std::sync::mpsc::{self, Receiver, RecvTimeoutError};
use std::sync::{Arc, Condvar, Mutex};
use std::thread::JoinHandle;
use std::time::{Duration, Instant};

use mindleak_core::config::DecayPolicy;
use mindleak_core::{MindLeak, MindLeakError};
use serde_json::json;

use super::config::MaintenanceConfig;

const SHUTDOWN_GRACE: Duration = Duration::from_secs(2);

#[derive(Clone)]
pub(crate) struct ActivitySignal {
    shared: Arc<(Mutex<ActivityState>, Condvar)>,
}

struct ActivityState {
    last_request: Instant,
    last_attempt: Option<Instant>,
    active_requests: usize,
    shutdown: bool,
}

impl ActivitySignal {
    pub(crate) fn new() -> Self {
        Self {
            shared: Arc::new((
                Mutex::new(ActivityState {
                    last_request: Instant::now(),
                    last_attempt: None,
                    active_requests: 0,
                    shutdown: false,
                }),
                Condvar::new(),
            )),
        }
    }

    pub(crate) fn begin_request(&self) -> RequestActivity {
        let (state, condition) = &*self.shared;
        let mut state = state.lock().unwrap_or_else(|error| error.into_inner());
        state.active_requests = state.active_requests.saturating_add(1);
        state.last_request = Instant::now();
        condition.notify_all();
        RequestActivity {
            activity: self.clone(),
        }
    }

    pub(crate) fn shutdown(&self) {
        let (state, condition) = &*self.shared;
        let mut state = state.lock().unwrap_or_else(|error| error.into_inner());
        state.shutdown = true;
        condition.notify_all();
    }

    fn is_shutdown(&self) -> bool {
        self.shared
            .0
            .lock()
            .unwrap_or_else(|error| error.into_inner())
            .shutdown
    }
}

pub(crate) struct RequestActivity {
    activity: ActivitySignal,
}

impl Drop for RequestActivity {
    fn drop(&mut self) {
        let (state, condition) = &*self.activity.shared;
        let mut state = state.lock().unwrap_or_else(|error| error.into_inner());
        state.active_requests = state.active_requests.saturating_sub(1);
        state.last_request = Instant::now();
        condition.notify_all();
    }
}

pub(crate) struct MaintenanceRuntime {
    activity: ActivitySignal,
    worker: Option<(JoinHandle<()>, Receiver<()>)>,
}

impl MaintenanceRuntime {
    pub(crate) fn disabled() -> Self {
        Self {
            activity: ActivitySignal::new(),
            worker: None,
        }
    }

    pub(crate) fn start(
        config: MaintenanceConfig,
        database_path: String,
        agent: Option<String>,
        decay_policy: DecayPolicy,
        working_set_size: usize,
    ) -> anyhow::Result<Self> {
        if !config.enabled {
            return Ok(Self::disabled());
        }
        if is_unsupported_maintenance_database(&database_path) {
            return Err(anyhow::anyhow!(
                "autonomous consolidation requires a file-backed MINDLEAK_DB"
            ));
        }
        // Open before spawning so an invalid path fails startup synchronously.
        let engine = MindLeak::open(&database_path)?
            .with_decay_policy(decay_policy)
            .with_working_set_size(working_set_size)
            .with_consolidation_min_interval(config.min_interval.as_secs())
            .with_agent(agent);
        let activity = ActivitySignal::new();
        let worker_activity = activity.clone();
        let (completed_tx, completed_rx) = mpsc::channel();
        let worker = std::thread::Builder::new()
            .name("mindleak-consolidation".to_string())
            .spawn(move || {
                run_worker(engine, worker_activity, config);
                let _ = completed_tx.send(());
            })?;
        Ok(Self {
            activity,
            worker: Some((worker, completed_rx)),
        })
    }

    pub(crate) fn activity(&self) -> ActivitySignal {
        self.activity.clone()
    }

    pub(crate) fn shutdown(self) {
        self.activity.shutdown();
        if let Some((worker, completed)) = self.worker {
            match completed.recv_timeout(SHUTDOWN_GRACE) {
                Ok(()) | Err(RecvTimeoutError::Disconnected) => {
                    let _ = worker.join();
                }
                Err(RecvTimeoutError::Timeout) => {
                    tracing::warn!(
                        "autonomous consolidation did not stop within shutdown grace; process exit will terminate it"
                    );
                }
            }
        }
    }
}

fn is_unsupported_maintenance_database(path: &str) -> bool {
    let normalized = path.trim().to_ascii_lowercase();
    normalized == ":memory:" || normalized.starts_with("file:")
}

fn run_worker(engine: MindLeak, activity: ActivitySignal, config: MaintenanceConfig) {
    loop {
        let (state, condition) = &*activity.shared;
        let mut state = state.lock().unwrap_or_else(|error| error.into_inner());
        if state.shutdown {
            break;
        }
        if state.active_requests > 0 {
            state = condition
                .wait(state)
                .unwrap_or_else(|error| error.into_inner());
            if state.shutdown {
                break;
            }
            continue;
        }
        let now = Instant::now();
        let idle_remaining = config
            .idle
            .saturating_sub(now.saturating_duration_since(state.last_request));
        let interval_remaining = state
            .last_attempt
            .map(|last| {
                config
                    .min_interval
                    .saturating_sub(now.saturating_duration_since(last))
            })
            .unwrap_or(Duration::ZERO);
        let wait = idle_remaining.max(interval_remaining);
        if !wait.is_zero() {
            let result = condition
                .wait_timeout(state, wait)
                .unwrap_or_else(|error| error.into_inner());
            state = result.0;
            if state.shutdown {
                break;
            }
            continue;
        }
        state.last_attempt = Some(Instant::now());
        drop(state);
        run_pass(
            &engine,
            config.max_nodes,
            config.min_interval.as_secs(),
            &activity,
        );
    }
}

fn run_pass(
    engine: &MindLeak,
    max_nodes: usize,
    min_interval_secs: u64,
    activity: &ActivitySignal,
) {
    let started = Instant::now();
    match engine
        .consolidate_signal_with_control(max_nodes, min_interval_secs, || activity.is_shutdown())
    {
        Ok(outcome) => {
            engine.record_maintenance(
                "autonomous_consolidation",
                "ok",
                started.elapsed().as_millis() as i64,
                Some(json!({
                    "candidates_consolidated": outcome.candidates_consolidated,
                    "edges_removed": outcome.edges_removed,
                    "nodes_removed": outcome.nodes_removed,
                })),
            );
            tracing::info!(
                candidates = outcome.candidates_consolidated,
                "autonomous consolidation completed"
            );
        }
        Err(MindLeakError::NotFound(_)) => {
            engine.record_maintenance(
                "autonomous_consolidation",
                "skipped",
                started.elapsed().as_millis() as i64,
                Some(json!({ "reason": "no_candidates" })),
            );
        }
        Err(MindLeakError::Busy(_)) => {
            engine.record_maintenance(
                "autonomous_consolidation",
                "skipped",
                started.elapsed().as_millis() as i64,
                Some(json!({ "reason": "lease_busy_or_rate_limited" })),
            );
        }
        Err(MindLeakError::Cancelled(_)) => {
            engine.record_maintenance(
                "autonomous_consolidation",
                "skipped",
                started.elapsed().as_millis() as i64,
                Some(json!({ "reason": "shutdown" })),
            );
        }
        Err(error) => {
            engine.record_maintenance(
                "autonomous_consolidation",
                "error",
                started.elapsed().as_millis() as i64,
                Some(json!({ "category": error_category(&error) })),
            );
            tracing::warn!(%error, "autonomous consolidation failed");
        }
    }
}

fn error_category(error: &MindLeakError) -> &'static str {
    match error {
        MindLeakError::Sqlite(_) => "sqlite",
        MindLeakError::Json(_) => "json",
        MindLeakError::Io(_) => "io",
        MindLeakError::Http(_) => "http",
        MindLeakError::NotFound(_) => "not_found",
        MindLeakError::Busy(_) => "busy",
        MindLeakError::Cancelled(_) => "cancelled",
        MindLeakError::Other(_) => "other",
    }
}

#[cfg(test)]
mod tests {
    use std::fs;
    use std::path::PathBuf;

    use super::*;

    #[test]
    fn shutdown_marks_state_and_wakes_waiters() {
        let activity = ActivitySignal::new();
        activity.shutdown();
        assert!(activity.shared.0.lock().unwrap().shutdown);
    }

    #[test]
    fn request_guard_tracks_activity_until_completion() {
        let activity = ActivitySignal::new();
        let guard = activity.begin_request();
        assert_eq!(activity.shared.0.lock().unwrap().active_requests, 1);
        drop(guard);
        assert_eq!(activity.shared.0.lock().unwrap().active_requests, 0);
    }

    #[test]
    fn disabled_runtime_has_no_worker_and_shuts_down() {
        MaintenanceRuntime::disabled().shutdown();
    }

    #[test]
    fn disabled_start_does_not_open_the_database() {
        let config = MaintenanceConfig::resolve(|_| None);
        let runtime = MaintenanceRuntime::start(
            config,
            "invalid\0database".to_string(),
            None,
            DecayPolicy::default(),
            7,
        )
        .unwrap();
        runtime.shutdown();
    }

    #[test]
    fn enabled_start_rejects_isolated_in_memory_database() {
        let config = MaintenanceConfig {
            enabled: true,
            idle: Duration::from_secs(30),
            min_interval: Duration::from_secs(60),
            max_nodes: 20,
        };
        let error = match MaintenanceRuntime::start(
            config,
            ":memory:".to_string(),
            None,
            DecayPolicy::default(),
            7,
        ) {
            Ok(runtime) => {
                runtime.shutdown();
                panic!("in-memory autonomous maintenance should be rejected");
            }
            Err(error) => error,
        };
        assert!(error.to_string().contains("file-backed"));
    }

    #[test]
    fn detects_sqlite_in_memory_uri_forms() {
        for path in [
            ":memory:",
            "file::memory:?cache=shared",
            "file:review?mode=memory",
            "FILE:review?cache=shared&MODE=MEMORY",
            "file:review?%6dode=memory",
            "file:review?mode=memory#fragment",
            "file:workspace.db?mode=rwc",
        ] {
            assert!(is_unsupported_maintenance_database(path), "{path}");
        }
        assert!(!is_unsupported_maintenance_database(
            "workspace/.mindleak/graph.db"
        ));
    }

    #[test]
    fn no_candidate_pass_records_skipped_maintenance_telemetry() {
        let engine = MindLeak::open_in_memory().unwrap();

        let activity = ActivitySignal::new();
        run_pass(&engine, 20, 0, &activity);

        let snapshot = engine.telemetry_snapshot(1).unwrap();
        assert_eq!(snapshot.recent[0].kind, "maintenance");
        assert_eq!(snapshot.recent[0].name, "autonomous_consolidation");
        assert_eq!(snapshot.recent[0].outcome, "skipped");
    }

    #[test]
    fn enabled_worker_runs_after_idle_and_joins_cleanly() {
        let path = temporary_database("idle");
        let runtime = MaintenanceRuntime::start(
            MaintenanceConfig {
                enabled: true,
                idle: Duration::from_millis(10),
                min_interval: Duration::from_secs(60),
                max_nodes: 20,
            },
            path.to_string_lossy().into_owned(),
            None,
            DecayPolicy::default(),
            7,
        )
        .unwrap();
        let inspector = MindLeak::open(path.to_str().unwrap()).unwrap();
        let deadline = Instant::now() + Duration::from_secs(2);
        loop {
            if inspector.telemetry_snapshot(1).unwrap().total_events > 0 {
                break;
            }
            assert!(Instant::now() < deadline, "idle worker did not run");
            let (state, condition) = &*runtime.activity.shared;
            let guard = state.lock().unwrap();
            let _ = condition
                .wait_timeout(guard, Duration::from_millis(5))
                .unwrap();
        }

        runtime.shutdown();
        drop(inspector);
        fs::remove_file(path).unwrap();
    }

    #[test]
    fn active_request_blocks_idle_pass_until_completion() {
        let path = temporary_database("active-request");
        let engine = MindLeak::open(path.to_str().unwrap()).unwrap();
        let inspector = MindLeak::open(path.to_str().unwrap()).unwrap();
        let activity = ActivitySignal::new();
        let request = activity.begin_request();
        let worker_activity = activity.clone();
        let worker = std::thread::spawn(move || {
            run_worker(
                engine,
                worker_activity,
                MaintenanceConfig {
                    enabled: true,
                    idle: Duration::from_millis(10),
                    min_interval: Duration::from_secs(60),
                    max_nodes: 20,
                },
            );
        });
        {
            let (state, condition) = &*activity.shared;
            let guard = state.lock().unwrap();
            let _ = condition
                .wait_timeout(guard, Duration::from_millis(30))
                .unwrap();
        }
        assert_eq!(inspector.telemetry_snapshot(1).unwrap().total_events, 0);

        drop(request);
        let deadline = Instant::now() + Duration::from_secs(2);
        while inspector.telemetry_snapshot(1).unwrap().total_events == 0 {
            assert!(
                Instant::now() < deadline,
                "worker did not run after request"
            );
            let (state, condition) = &*activity.shared;
            let guard = state.lock().unwrap();
            let _ = condition
                .wait_timeout(guard, Duration::from_millis(5))
                .unwrap();
        }

        activity.shutdown();
        worker.join().unwrap();
        drop(inspector);
        fs::remove_file(path).unwrap();
    }

    fn temporary_database(name: &str) -> PathBuf {
        let path = std::env::temp_dir().join(format!(
            "mindleak-maintenance-{name}-{}.db",
            std::process::id()
        ));
        let _ = fs::remove_file(&path);
        path
    }
}
